import React, { useState } from 'react';
import './styles.css';

const App = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [darkMode, setDarkMode] = useState(false);

  const handleLogin = () => {
    console.log('Login button clicked');
  };

  return (
    <div className={`min-h-screen bg-[#090a0f] text-white p-4 ${darkMode ? 'dark' : ''} flex items-center justify-center`}>      
      <div className='bg-[#B7D7CD] p-4 rounded-lg shadow-md'>        
        <h2 className='text-lg font-bold mb-4'>Login Panel</h2>
        <div className='mb-4'>          
          <input
type='text'
          className='w-full p-2 rounded-md'
          value={username}
          onChange={e => setUsername(e.target.value)}
          placeholder='Username'/>
        </div>
        <div className='mb-4'>          
          <input
type='password'
          className='w-full p-2 rounded-md'
          value={password}
          onChange={e => setPassword(e.target.value)}
          placeholder='Password'/>
        </div>
        <button
className='bg-[#C06C88] p-2 rounded-md text-white hover:bg-[#411C56]'
        onClick={handleLogin}
        >Login</button>
        <button
className='ml-4 bg-[#C06C88] p-2 rounded-md text-white hover:bg-[#411C56]'
        onClick={() => setDarkMode(!darkMode)}
        >Toggle Dark Mode</button>
      </div>
    </div>
  );
};

export default App;
